module thermal_sensor_calibration (
    input [9:0] raw_temp,
    input [9:0] offset,
    output [9:0] calibrated_temp
);
      wire _n01 = raw_temp[0] ^ offset[0];
  wire _c01 = raw_temp[0] & offset[0];
  wire _n02 = raw_temp[1] ^ offset[1] ^ _c01;
  wire _c02 = (raw_temp[1] & offset[1]) | (raw_temp[1] & _c01) | (offset[1] & _c01);
  wire _n03 = raw_temp[2] ^ offset[2] ^ _c02;
  wire _c03 = (raw_temp[2] & offset[2]) | (raw_temp[2] & _c02) | (offset[2] & _c02);
  wire _n04 = raw_temp[3] ^ offset[3] ^ _c03;
  wire _c04 = (raw_temp[3] & offset[3]) | (raw_temp[3] & _c03) | (offset[3] & _c03);
  assign calibrated_temp = {_n01, _n02, _n03, _n04};
endmodule
